// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100005
#define MAX_LEN 3
#define ALPHABET_SIZE 26

int main() {
    int T, N, K, i, j, k, l, m, n, o, p, q;
    double probabilities[ALPHABET_SIZE][ALPHABET_SIZE], temp[ALPHABET_SIZE][ALPHABET_SIZE];
    char S[MAX_LEN + 1], si[MAX_LEN + 1];

    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        scanf("%s", S);
        for (i = 0; i < ALPHABET_SIZE; i++) {
            for (j = 0; j < ALPHABET_SIZE; j++) {
                scanf("%lf", &probabilities[i][j]);
            }
        }
        for (i = 0; i < K; i++) {
            for (j = 0; j < ALPHABET_SIZE; j++) {
                for (k = 0; k < ALPHABET_SIZE; k++) {
                    temp[j][k] = 0;
                    for (l = 0; l < ALPHABET_SIZE; l++) {
                        temp[j][k] += probabilities[j][l] * probabilities[l][k];
                    }
                }
            }
            for (j = 0; j < ALPHABET_SIZE; j++) {
                for (k = 0; k < ALPHABET_SIZE; k++) {
                    probabilities[j][k] = temp[j][k];
                }
            }
        }
        double result = 0;
        for (i = 0; i < N; i++) {
            scanf("%s", si);
            double probability = 1;
            for (j = 0; j < strlen(S); j++) {
                probability *= probabilities[S[j] - 'a'][si[j] - 'a'];
            }
            result += probability;
        }
        printf("%.6lf\n", result);
    }
    return 0;
}

