// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int K = scanner.nextInt();
            String S = scanner.next();
            double[][] probabilities = new double[26][26];
            for (int i = 0; i < 26; i++) {
                for (int j = 0; j < 26; j++) {
                    probabilities[i][j] = scanner.nextDouble();
                }
            }
            double[][] temp = new double[26][26];
            for (int i = 0; i < K; i++) {
                for (int j = 0; j < 26; j++) {
                    for (int k = 0; k < 26; k++) {
                        temp[j][k] = 0;
                        for (int l = 0; l < 26; l++) {
                            temp[j][k] += probabilities[j][l] * probabilities[l][k];
                        }
                    }
                }
                for (int j = 0; j < 26; j++) {
                    for (int k = 0; k < 26; k++) {
                        probabilities[j][k] = temp[j][k];
                    }
                }
            }
            double result = 0;
            for (int i = 0; i < N; i++) {
                String si = scanner.next();
                double probability = 1;
                for (int j = 0; j < S.length(); j++) {
                    probability *= probabilities[S.charAt(j) - 'a'][si.charAt(j) - 'a'];
                }
                result += probability;
            }
            System.out.printf("%.6f\n", result);
        }
    }
}

