import sys
input = sys.stdin.readline

T = int(input())
for _ in range(T):
    N, K = map(int, input().split())
    S = input().rstrip()
    probabilities = [list(map(float, input().split())) for _ in range(26)]
    for _ in range(K):
        temp = [[0] * 26 for _ in range(26)]
        for i in range(26):
            for j in range(26):
                for k in range(26):
                    temp[i][j] += probabilities[i][k] * probabilities[k][j]
        probabilities = temp
    result = 0
    for _ in range(N):
        si = input().rstrip()
        probability = 1
        for i in range(len(S)):
            probability *= probabilities[ord(S[i]) - ord('a')][ord(si[i]) - ord('a')]
        result += probability
    print(f'{result:.6f}')

